// MHPCO Claim Office implementation

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioOutput {
  results: StepResult[];
}

// Item specifications
const MAIN_ITEMS: Record<string, { insuranceValue: number; basePremium: number }> = {
  sword:  { insuranceValue: 1000, basePremium: 100 },
  amulet: { insuranceValue: 600,  basePremium: 60  },
  staff:  { insuranceValue: 800,  basePremium: 80  },
  potion: { insuranceValue: 400,  basePremium: 40  },
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

function isComponent(type: string): boolean {
  return COMPONENT_TYPES.has(type);
}

function isKnownType(type: string): boolean {
  return type in MAIN_ITEMS || isComponent(type);
}

function itemInsuranceValue(type: string): number {
  if (type in MAIN_ITEMS) return MAIN_ITEMS[type].insuranceValue;
  if (isComponent(type)) return 250;
  throw new Error(`Unknown item type: ${type}`);
}

// Item-specific surcharge component (curse + high enchantment) for a main item.
function mainItemSurcharges(item: Item): number {
  const spec = MAIN_ITEMS[item.type];
  if (!spec) throw new Error(`Not a main item: ${item.type}`);
  let surcharge = 0;
  if (item.cursed) {
    surcharge += spec.basePremium * 0.5;
  }
  if ((item.enchantment ?? 0) >= 5) {
    surcharge += spec.basePremium * 0.3;
  }
  return surcharge;
}

// Compute the base premium contribution of the components grouped by type.
// A "block" discount (60 G) applies only when the count of a given component type is exactly 3.
function componentsBasePremium(components: Item[]): number {
  const byType: Record<string, number> = {};
  for (const c of components) {
    byType[c.type] = (byType[c.type] ?? 0) + 1;
  }
  let total = 0;
  for (const count of Object.values(byType)) {
    if (count === 3) {
      total += 60;
    } else {
      total += count * 25;
    }
  }
  return total;
}

// Quote calculation
export function computeQuote(
  customer: Customer,
  items: Item[],
  isFollowUpContract: boolean,
): number {
  // Validate types
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  const mainItems = items.filter(i => i.type in MAIN_ITEMS);
  const components = items.filter(i => isComponent(i.type));

  // Policy base premium: sum of all items' (unmodified) base premiums.
  // For main items, that's the per-item base; for components, the block-discounted total.
  let policyBase = 0;
  for (const item of mainItems) {
    policyBase += MAIN_ITEMS[item.type].basePremium;
  }
  policyBase += componentsBasePremium(components);

  // Item-specific surcharges (cursed, high enchantment) attach to individual main items.
  let itemSurcharges = 0;
  for (const item of mainItems) {
    itemSurcharges += mainItemSurcharges(item);
  }

  // Policy-wide modifiers apply to policyBase.
  let premium = policyBase + itemSurcharges;
  if (customer.yearsWithMHPCO >= 2) {
    premium -= policyBase * 0.2;
  }
  // First insurance surcharge: 10% of policyBase.
  premium += policyBase * 0.1;

  if (isFollowUpContract) {
    premium -= policyBase * 0.15;
  }

  // Processing fee
  premium += 5;

  // Round up (in the MHPCO's favor)
  return Math.ceil(premium);
}

// Policy state for claim processing
export interface Policy {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

export function createPolicy(items: Item[]): Policy {
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
  const insuranceSum = items.reduce((s, i) => s + itemInsuranceValue(i.type), 0);
  const cap = 2 * insuranceSum;
  return { items, insuranceSum, cap, remainingCap: cap };
}

// Reimbursement for a single damage entry. When both the high-enchantment (≥8) and
// dragon-material clauses apply, the 50 % high-enchantment rule wins. Deductible applies last.
function damageReimbursement(item: Item, amount: number): number {
  let reimbursable: number;
  if ((item.enchantment ?? 0) >= 8) {
    reimbursable = amount * 0.5;
  } else if (item.material === "dragon") {
    reimbursable = amount;
  } else {
    reimbursable = amount;
  }
  return Math.max(0, reimbursable - 100);
}

export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
  // Validate damage entries: types are known, amounts non-negative, item counts match
  const policyTypeCounts: Record<string, number> = {};
  for (const item of policy.items) {
    policyTypeCounts[item.type] = (policyTypeCounts[item.type] ?? 0) + 1;
  }

  const damageTypeCounts: Record<string, number> = {};
  for (const d of incident.damages) {
    if (d.amount < 0) {
      throw new Error(`Negative damage amount: ${d.amount}`);
    }
    if (!isKnownType(d.itemType)) {
      throw new Error(`Unknown item type in damage: ${d.itemType}`);
    }
    damageTypeCounts[d.itemType] = (damageTypeCounts[d.itemType] ?? 0) + 1;
  }
  for (const [type, count] of Object.entries(damageTypeCounts)) {
    if ((policyTypeCounts[type] ?? 0) < count) {
      throw new Error(`Damage references item not covered by policy: ${type}`);
    }
  }

  // Match damages to items in order
  // For each damage entry, find a matching item of the same type to compute its reimbursement
  const itemsByType: Record<string, Item[]> = {};
  for (const item of policy.items) {
    if (!itemsByType[item.type]) itemsByType[item.type] = [];
    itemsByType[item.type].push(item);
  }
  // Make per-type indexes that consume items in order
  const consumedIndex: Record<string, number> = {};

  let totalPayout = 0;
  for (const damage of incident.damages) {
    const list = itemsByType[damage.itemType] ?? [];
    const idx = consumedIndex[damage.itemType] ?? 0;
    const item = list[idx];
    consumedIndex[damage.itemType] = idx + 1;

    const reimbursementFractional = damageReimbursement(item, damage.amount);
    // Round down (in MHPCO's favor) per damage entry, then apply cap
    // Spec: only the final payout is rounded
    totalPayout += reimbursementFractional;
  }

  // Round down final payout
  let payout = Math.floor(totalPayout);

  // Apply cap
  if (payout > policy.remainingCap) {
    payout = policy.remainingCap;
  }
  policy.remainingCap -= payout;

  return { payout, remainingCap: policy.remainingCap };
}

export function runScenario(scenario: Scenario): ScenarioOutput {
  const results: StepResult[] = [];
  const policies: (Policy | null)[] = [];
  let priorQuoteCount = 0;

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const isFollowUp = priorQuoteCount >= 1;
      const premium = computeQuote(scenario.customer, step.items, isFollowUp);
      results.push({ premium });
      policies.push(createPolicy(step.items));
      priorQuoteCount += 1;
    } else if (step.op === "claim") {
      const policy = policies[step.policy];
      if (!policy) {
        throw new Error(`Claim references unknown policy: ${step.policy}`);
      }
      const r = processClaim(policy, step.incident);
      results.push(r);
      policies.push(null);
    } else {
      throw new Error(`Unknown op: ${(step as any).op}`);
    }
  }

  return { results };
}

